mapper.select:
SELECT h.hotel_id AS hotelId, h.hotel_name AS hotelName, h.phone AS phone, h.province AS province, h.city AS city, h.district AS district, h.address AS address, CONCAT_WS('', NULLIF(h.province, ''), NULLIF(h.city, ''), NULLIF(h.district, ''), NULLIF(h.address, '')) AS fullAddress, h.description AS description, h.price_min AS minPrice, h.rating AS rating, h.picture AS picture, h.has_wifi AS hasWifi, h.has_breakfast AS hasBreakfast, h.has_parking AS hasParking,
( SELECT GROUP_CONCAT(DISTINCT rt_match.type_name SEPARATOR ',') FROM room_type rt_match WHERE rt_match.hotel_id = h.hotel_id AND rt_match.is_delete = 0
AND rt_match.type_id = #{roomTypeId}
AND rt_match.type_name LIKE CONCAT('%', #{roomTypeKeyword}, '%')
) AS matchedRoomTypesRaw,
NULL AS matchedRoomTypesRaw,
COALESCE(( SELECT SUM(
GREATEST( rt.capacity - COALESCE(( SELECT SUM(r.room_count) FROM reservation r WHERE r.hotel_id = h.hotel_id AND r.type_id = rt.type_id AND r.status IN (1, 2, 4) AND r.is_delete = 0 AND r.check_in_date < #{checkOutDate} AND r.check_out_date > #{checkInDate} ), 0), 0 )
rt.capacity
) FROM room_type rt WHERE rt.hotel_id = h.hotel_id AND rt.is_delete = 0 ), 0) AS availableRoomCount FROM hotel h
h.is_delete = 0
AND h.province LIKE CONCAT('%', #{province}, '%')
AND h.city LIKE CONCAT('%', #{city}, '%')
AND h.district LIKE CONCAT('%', #{district}, '%')
AND ( h.district LIKE CONCAT('%', #{districtKeyword}, '%') OR h.address LIKE CONCAT('%', #{districtKeyword}, '%') )
AND h.address LIKE CONCAT('%', #{street}, '%')
AND h.address LIKE CONCAT('%', #{addressKeyword}, '%')
AND h.hotel_name LIKE CONCAT('%', #{hotelName}, '%')
AND h.price_max >= #{minPrice}
AND h.price_min <= #{maxPrice}
AND h.rating >= #{rating}
AND EXISTS ( SELECT 1 FROM room_type rt_filter WHERE rt_filter.hotel_id = h.hotel_id AND rt_filter.is_delete = 0
AND rt_filter.type_id = #{roomTypeId}
AND rt_filter.type_name LIKE CONCAT('%', #{roomTypeKeyword}, '%')
)
AND h.has_wifi = 1
AND h.has_breakfast = 1
AND h.has_parking = 1
AND (
h.has_wifi = 1 OR
h.has_breakfast = 1 OR
h.has_parking = 1 OR
)
AND (
(CASE WHEN h.has_wifi = 1 THEN 1 ELSE 0 END) +
(CASE WHEN h.has_breakfast = 1 THEN 1 ELSE 0 END) +
(CASE WHEN h.has_parking = 1 THEN 1 ELSE 0 END) +
0 ) >= #{facilityMinMatchCount}
AND EXISTS ( SELECT 1 FROM room_type rt WHERE rt.hotel_id = h.hotel_id AND rt.is_delete = 0
AND GREATEST( rt.capacity - COALESCE(( SELECT SUM(r.room_count) FROM reservation r WHERE r.hotel_id = h.hotel_id AND r.type_id = rt.type_id AND r.status IN (1, 2, 4) AND r.is_delete = 0 AND r.check_in_date < #{checkOutDate} AND r.check_out_date > #{checkInDate} ), 0), 0 ) >= #{roomCount}
AND rt.capacity >= #{roomCount}
)
ORDER BY CASE WHEN #{hotelName} IS NOT NULL AND #{hotelName} != '' AND h.hotel_name LIKE CONCAT(#{hotelName}, '%') THEN 500 WHEN #{roomTypeKeyword} IS NOT NULL AND #{roomTypeKeyword} != '' AND EXISTS ( SELECT 1 FROM room_type rt_score WHERE rt_score.hotel_id = h.hotel_id AND rt_score.is_delete = 0 AND rt_score.type_name LIKE CONCAT('%', #{roomTypeKeyword}, '%') ) THEN 420 WHEN #{roomTypeId} IS NOT NULL AND EXISTS ( SELECT 1 FROM room_type rt_score WHERE rt_score.hotel_id = h.hotel_id AND rt_score.is_delete = 0 AND rt_score.type_id = #{roomTypeId} ) THEN 400 WHEN #{district} IS NOT NULL AND #{district} != '' AND h.district = #{district} THEN 350 WHEN #{districtKeyword} IS NOT NULL AND #{districtKeyword} != '' AND h.district LIKE CONCAT('%', #{districtKeyword}, '%') THEN 300 WHEN #{districtKeyword} IS NOT NULL AND #{districtKeyword} != '' AND h.address LIKE CONCAT('%', #{districtKeyword}, '%') THEN 260 WHEN #{street} IS NOT NULL AND #{street} != '' AND h.address LIKE CONCAT('%', #{street}, '%') THEN 240 WHEN #{addressKeyword} IS NOT NULL AND #{addressKeyword} != '' AND h.address LIKE CONCAT('%', #{addressKeyword}, '%') THEN 220 WHEN #{city} IS NOT NULL AND #{city} != '' AND h.city LIKE CONCAT('%', #{city}, '%') THEN 180 ELSE 0 END DESC, COALESCE(h.rating, 0) DESC, COALESCE(h.price_min, 0) ASC, h.hotel_id DESC
